SELECT COUNT(*) AS total_matches
FROM match_data
WHERE club_id = 1;

SELECT club_id, COUNT(*) AS total_matches
FROM match_data
GROUP BY club_id;

SELECT owner_name, MAX(team_value) AS highest_team_value
FROM clubs
WHERE team_value = (SELECT MAX(team_value) FROM clubs);

SELECT match_date, result, goals_scored, goals_conceded
FROM match_data
WHERE club_id = 1;
